import {
  tagForUrl,
  buildSearchIndexes,
  SEARCH_TAGS,
} from "@/lib/search-indexes";

// Pull every content string out of a record's structuredData for assertions.
function bodyText(record: { structuredData?: { contents: { content: string }[] } }): string {
  return (record.structuredData?.contents ?? [])
    .map((c) => c.content)
    .join("\n");
}

describe("tagForUrl", () => {
  const cases: [string, string][] = [
    ["/docs/reference/skills/assess", "skill"],
    ["/docs/skills/overview", "skill"],
    ["/docs/reference/agents/x", "agent"],
    ["/docs/agents/overview", "agent"],
    ["/docs/reference/hooks/x", "hook"],
    ["/docs/hooks/overview", "hook"],
    ["/docs/foundations/overview", "docs"],
    ["/docs", "docs"],
  ];

  for (const [url, expected] of cases) {
    it(`${url} -> ${expected}`, () => {
      const tag = tagForUrl(url);
      expect(tag).toBe(expected);
      expect(SEARCH_TAGS).toContain(tag);
    });
  }
});

describe("buildSearchIndexes", () => {
  const records = buildSearchIndexes();
  const byId = new Map(records.map((r) => [r.id, r]));

  it("emits one record per page plus one per composition", () => {
    // 3 mock pages + 1 composition
    expect(records).toHaveLength(4);
  });

  it("every record carries a tag in SEARCH_TAGS", () => {
    for (const r of records) {
      expect(SEARCH_TAGS).toContain(r.tag);
    }
  });

  it("tags each page by its URL", () => {
    expect(byId.get("/docs/foundations/overview")?.tag).toBe("docs");
    expect(byId.get("/docs/reference/skills/assess")?.tag).toBe("skill");
    expect(byId.get("/docs/reference/agents/foo")?.tag).toBe("agent");
  });

  it("enriches the skill record with its tags AND full body", () => {
    const skill = byId.get("/docs/reference/skills/assess");
    expect(skill?.tag).toBe("skill");
    const text = bodyText(skill ?? {});
    // Original summary preserved.
    expect(text).toContain("Skill summary line.");
    // Tags joined and appended.
    expect(text).toContain("quality, scoring");
    // Full skill body injected for deep-content search.
    expect(text).toContain("ASSESS_BODY_MARKER");
  });

  it("enriches the agent record with keywords and task types", () => {
    const agent = byId.get("/docs/reference/agents/foo");
    expect(agent?.tag).toBe("agent");
    const text = bodyText(agent ?? {});
    expect(text).toContain("FOO_KEYWORD_MARKER");
    // taskTypes joined: "build, test"
    expect(text).toContain("build, test");
  });

  it("leaves a plain docs page unenriched (no skill/agent extras)", () => {
    const docs = byId.get("/docs/foundations/overview");
    const text = bodyText(docs ?? {});
    expect(text).toContain("Plain docs prose body.");
    expect(text).not.toContain("ASSESS_BODY_MARKER");
  });

  it("injects a synthetic composition record", () => {
    const comp = byId.get("composition-implement-cover");
    expect(comp).toBeDefined();
    expect(comp?.tag).toBe("composition");
    expect(comp?.url).toContain("/showcase/pipeline#");
    expect(comp?.url).toContain("implement-cover");
    const text = bodyText(comp ?? {});
    expect(text).toContain("COMP_HOOK_MARKER");
    expect(text).toContain("COMP_TAG_MARKER");
  });
});
